// ============================================================
// PREPARE FINAL DATA
// Reads initial_vulnerabilities from static data (saved on
// first loop pass in JSON Output Parser). Gets true original
// code directly from Webhook input. Cleans up static data.
// ============================================================

for (const item of items) {
  try {
    const staticData = $getWorkflowStaticData('global');
    const execId = ($execution && $execution.id)
      ? String($execution.id)
      : 'run_' + Date.now();
    const runData = (staticData.runs && staticData.runs[execId])
      ? staticData.runs[execId]
      : {};
    const initialVulns = runData.initial_vulnerabilities || [];

    // Response metrics
    item.json.number_of_vulnerabilities_fixed = initialVulns.length;
    const types = initialVulns.map(v => v.type || 'Unknown');
    item.json.types_of_vulnerabilities = [...new Set(types)];
    item.json.vulnerabilities_details = initialVulns.map(v => ({
      type: v.type || 'Unknown',
      original_line_number: v.line_number || 0
    }));

    // Pass through full vulnerability mappings (original_code/fixed_code)
    // The extension needs these for in-place code replacement
    item.json.vulnerabilities = initialVulns;

    // True original = raw webhook input (before Syntax Fixer touched it)
    try {
      item.json.absolute_original_code = $('Webhook').first().json.body.code;
    } catch (e) {
      item.json.absolute_original_code =
        $('Init Loop Counter').first()?.json?.original_code || '';
    }

    // Ensure corrected code is always populated
    if (!item.json.full_corrected_code) {
      item.json.full_corrected_code =
        item.json.audited_code ||
        $('Max Retries Reached?').first()?.json?.code || '';
    }

    // Cleanup static data for this execution
    if (staticData.runs && staticData.runs[execId]) {
      delete staticData.runs[execId];
    }

  } catch (error) {
    item.json.error = 'Failed to prepare final data: ' + error.message;
  }
}
return items;

